/* ═══════════════════════════════════════
   IGNIS ORIGINS — AD SYSTEM (HQ)
   Agrega: <script src="ignis_ads.js"></script> antes de </body>
═══════════════════════════════════════ */

(function () {
    'use strict';

    const _adImages = [
        'data:image/webp;base64,',
        'data:image/webp;base64,',
        'data:image/webp;base64,',
        'data:image/webp;base64,',
        'data:image/webp;base64,',
        'data:image/webp;base64,',
        'data:image/webp;base64,',
    ];
    let _adIndex = 0;

    const _style = document.createElement('style');
    _style.textContent = `
        /* ═══════════════════════════════════════
           AD MODAL SYSTEM
        ═══════════════════════════════════════ */
        #ad-overlay {
            display: none;
            position: fixed;
            inset: 0;
            z-index: 99999;
            backdrop-filter: blur(12px);
            -webkit-backdrop-filter: blur(12px);
            background: rgba(0, 0, 0, 0.7);
            align-items: center;
            justify-content: center;
            animation: adFadeIn .3s ease;
        }
        #ad-overlay.visible {
            display: flex;
        }
        @keyframes adFadeIn {
            from { opacity: 0; }
            to { opacity: 1; }
        }
        .ad-modal {
            position: relative;
            max-width: 460px;
            width: calc(100% - 48px);
            animation: adSlideUp .38s cubic-bezier(.34, 1.56, .64, 1);
        }
        @keyframes adSlideUp {
            from { opacity: 0; transform: translateY(50px) scale(0.92); }
            to   { opacity: 1; transform: none; }
        }
        .ad-close-btn {
            position: absolute;
            top: -18px;
            right: -18px;
            width: 40px;
            height: 40px;
            border-radius: 50%;
            background: linear-gradient(135deg, #c0370d, #f5a623);
            border: 2.5px solid rgba(255, 255, 255, 0.4);
            color: #fff;
            font-size: 20px;
            font-weight: 800;
            cursor: pointer;
            display: flex;
            align-items: center;
            justify-content: center;
            z-index: 100001;
            box-shadow: 0 6px 24px rgba(0, 0, 0, 0.55), 0 0 0 0 rgba(245,166,35,0);
            transition: transform .22s cubic-bezier(.34,1.56,.64,1), box-shadow .22s;
            line-height: 1;
            font-family: 'DM Sans', sans-serif;
            padding: 0;
        }
        .ad-close-btn:hover {
            transform: scale(1.18) rotate(90deg);
            box-shadow: 0 8px 32px rgba(192, 55, 13, 0.75);
        }
        .ad-img {
            width: 100%;
            height: auto;
            display: block;
            border-radius: 18px;
            box-shadow:
                0 24px 70px rgba(0, 0, 0, 0.65),
                0 0 0 1.5px rgba(200, 55, 13, 0.35);
        }
        .ad-label {
            position: absolute;
            top: 12px;
            left: 12px;
            font-family: 'DM Mono', monospace;
            font-size: 10px;
            letter-spacing: 2px;
            text-transform: uppercase;
            color: rgba(255, 255, 255, 0.45);
            background: rgba(0, 0, 0, 0.55);
            padding: 3px 9px;
            border-radius: 5px;
            pointer-events: none;

            /* ── Ad size variants ── */
#ad-overlay[data-size="large"] .ad-modal  { max-width: 500px; }
#ad-overlay[data-size="wide"]  .ad-modal  { max-width: 720px; }
#ad-overlay[data-size="xl"]    .ad-modal  { max-width: 600px; }
        }`;
    document.head.appendChild(_style);

    const _modal = document.createElement('div');
    _modal.id = 'ad-overlay';
    _modal.innerHTML = `
        <div class="ad-modal">
            <span class="ad-label">Publicidad</span>
            <button class="ad-close-btn" id="ad-close-btn" title="Cerrar anuncio">&#x2715;</button>
            <img id="ad-img" class="ad-img" src="" alt="Anuncio">
        </div>`;
    document.body.appendChild(_modal);

    // Size map: index → data-size attribute
    const _adSizes = {
        0: 'large',   // AO3 (portrait, bigger)
        6: 'wide',    // CONAMAT 1 (landscape)
        7: 'wide',    // CONAMAT 2 (landscape)
        8: 'xl',      // CONAMAT 3 (square)
        9: 'wide'     // CONAMAT 4 (landscape)
    };

    window.showAd = function () {
        const overlay = document.getElementById('ad-overlay');
        const img = document.getElementById('ad-img');
        const idx = _adIndex % _adImages.length;
        img.src = _adImages[idx];
        // Apply size variant
        const size = _adSizes[idx] || 'normal';
        overlay.dataset.size = size;
        _adIndex++;
        overlay.classList.add('visible');
    };

    window.closeAd = function () {
        document.getElementById('ad-overlay').classList.remove('visible');
    };

    _modal.addEventListener('click', function (e) {
        if (e.target === this) window.closeAd();
    });

    document.getElementById('ad-close-btn').addEventListener('click', window.closeAd);

    document.addEventListener('DOMContentLoaded', function () {
        const AD_PAGES = ['articulo1', 'articulo2', 'articulo3',
            'articulo4', 'articulo5', 'juegos', 'conclusiones'];
        if (typeof showPage === 'function') {
            const _origSP = window.showPage;
            window.showPage = function (name) {
                _origSP(name);
                if (AD_PAGES.includes(name)) {
                    setTimeout(window.showAd, 650);
                }
            };
        }
    });

})();